mapper.sql:
from book_borrow_detail d inner join book_borrow_order o on o.id = d.borrow_order_id and o.is_del = 0 where d.is_del = 0
and o.member_phone like concat('%', #{phone}, '%')
and d.borrow_status = #{status}
and d.member_id = #{memberId}
and d.borrow_qty > coalesce(d.returned_qty, 0) + coalesce(d.purchase_qty, 0)

mapper.update:
update book_borrow_detail
returned_qty = #{returnedQty}, borrow_status = #{borrowStatus}, return_all_time = #{returnAllTime}, last_staff_id = #{lastStaffId}, last_staff_name = #{lastStaffName}, updated_at = now()
where id = #{id}

update book_borrow_detail
purchase_qty = #{purchaseQty}, purchase_order_no = #{purchaseOrderNo}, borrow_status = #{borrowStatus}, return_all_time = #{returnAllTime}, last_staff_id = #{lastStaffId}, last_staff_name = #{lastStaffName}, updated_at = now()
where id = #{id}
